def gen(rng, size):
    n = max(2, min(size, 20000))
    common_count = max(1, n // 4)
    common_list = sorted(rng.sample(range(1, 5000000), common_count))
    common_set = set(common_list)
    def build(extra_count):
        extra = set()
        while len(extra) < extra_count:
            v = rng.randint(1, 5000000)
            if v not in common_set and v not in extra:
                extra.add(v)
        return sorted(common_list + list(extra))
    nums1 = build(n - common_count)
    nums2 = build(n - common_count)
    return [nums1, nums2]

