    let i = 0, j = 0;
    const n1 = nums1.length, n2 = nums2.length;
    let sum1 = 0, sum2 = 0;
    while (i < n1 && j < n2) {
        if (nums1[i] < nums2[j]) {
            sum1 += nums1[i];
            i += 1;
        } else if (nums1[i] > nums2[j]) {
            sum2 += nums2[j];
            j += 1;
        } else {
            sum1 = sum2 = Math.max(sum1, sum2) + nums1[i];
            i += 1;
            j += 1;
        }
    }
    while (i < n1) { sum1 += nums1[i]; i += 1; }
    while (j < n2) { sum2 += nums2[j]; j += 1; }
    return Math.max(sum1, sum2) % MOD;
